+function findOptionDependency(usage: Usage): OptionDependency | undefined {
+  for (const term of usage) {
+    if (term.type === "option" && term.dependsOn !== undefined) {
+      return term.dependsOn;
+    }
+    if (term.type === "optional" || term.type === "multiple") {
+      const dependency = findOptionDependency(term.terms);
+      if (dependency !== undefined) return dependency;
+    } else if (term.type === "exclusive") {
+      for (const terms of term.terms) {
+        const dependency = findOptionDependency(terms);
+        if (dependency !== undefined) return dependency;
+      }
+    }
+  }
+  return undefined;
+}
+
+function findOptionNames(usage: Usage): readonly string[] {
+  const names: string[] = [];
+  for (const term of usage) {
+    if (term.type === "option") names.push(...term.names);
+    else if (term.type === "optional" || term.type === "multiple") {
+      names.push(...findOptionNames(term.terms));
+    } else if (term.type === "exclusive") {
+      for (const terms of term.terms) names.push(...findOptionNames(terms));
+    }
+  }
+  return names;
+}
+
+function stateValue(state: unknown): unknown {
+  if (Array.isArray(state) && state.length === 1) return stateValue(state[0]);
+  if (isDependencySourceState(state)) return stateValue(state.result);
+  if (state != null && typeof state === "object" && "success" in state) {
+    const result = state as { success: unknown; value?: unknown };
+    return result.success === true ? result.value : undefined;
+  }
+  return state;
+}
+
+function dependencyConditions(
+  dependency: OptionDependency,
+): { readonly allOf: readonly OptionDependencyCondition[]; readonly anyOf?: readonly OptionDependencyCondition[] } {
+  if (typeof dependency === "string" || "option" in dependency) {
+    return { allOf: [dependency] };
+  }
+  return { allOf: dependency.allOf ?? [], anyOf: dependency.anyOf };
+}
+
+function conditionOption(condition: OptionDependencyCondition): string {
+  return typeof condition === "string" ? condition : condition.option;
+}
+
+function conditionSatisfied(
+  condition: OptionDependencyCondition,
+  values: Readonly<Record<string | symbol, unknown>>,
+  resolveKey: (reference: string) => string | symbol | undefined,
+): boolean {
+  const key = resolveKey(conditionOption(condition));
+  if (key === undefined) return false;
+  const value = values[key];
+  return typeof condition === "string" || !("value" in condition)
+    ? Boolean(value)
+    : value === condition.value;
+}
+
+function dependencySatisfied(
+  dependency: OptionDependency,
+  values: Readonly<Record<string | symbol, unknown>>,
+  resolveKey: (reference: string) => string | symbol | undefined,
+): boolean {
+  const { allOf, anyOf } = dependencyConditions(dependency);
+  return allOf.every((condition) => conditionSatisfied(condition, values, resolveKey)) &&
+    (anyOf === undefined || anyOf.some((condition) => conditionSatisfied(condition, values, resolveKey)));
+}
